example.code:
using ByteForge.Toolkit;

// Initialize core WinSCP resources on application startup
try
{
    #if NETFRAMEWORK
    Core.EnsureWinSCP();
    Console.WriteLine("WinSCP resources successfully extracted");
    #endif
}
catch (Exception ex)
{
    Console.WriteLine($"Failed to initialize WinSCP: {ex.Message}");
    // Application may continue with limited functionality
}

// Now WinSCP functionality is available
using (var session = new WinSCP.Session())
{
    var sessionOptions = new WinSCP.SessionOptions
    {
        Protocol = WinSCP.Protocol.Sftp,
        HostName = "example.com",
        UserName = "user",
        Password = "password"
    };

    session.Open(sessionOptions);

    // Transfer files
    WinSCP.TransferOptions transferOptions = new WinSCP.TransferOptions();
    transferOptions.TransferMode = WinSCP.TransferMode.Binary;

    WinSCP.TransferOperationResult transferResult;
    transferResult = session.PutFiles(@"d:\toupload\*", "/home/user/", false, transferOptions);

    // Check for transfer errors
    transferResult.Check();

    Console.WriteLine("Upload successful");
}

public class WinScpManager
{
    private bool _resourcesInitialized = false;

    public bool InitializeWinScpResources()
    {
        if (_resourcesInitialized)
            return true;

        try
        {
            #if NETFRAMEWORK
            Console.WriteLine("Initializing WinSCP resources...");
            Core.EnsureWinSCP();

            // Verify WinSCP executable exists
            string winScpPath = Path.Combine(
                Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location), 
                "WinSCP.exe"
            );

            if (File.Exists(winScpPath))
            {
                var fileInfo = new FileInfo(winScpPath);
                Console.WriteLine($"WinSCP.exe found: {fileInfo.Length:N0} bytes");

                // Test executable version
                var processInfo = new ProcessStartInfo
                {
                    FileName = winScpPath,
                    Arguments = "/help",
                    UseShellExecute = false,
                    RedirectStandardOutput = true,
                    CreateNoWindow = true
                };

                using (var process = Process.Start(processInfo))
                {
                    process.WaitForExit(5000); // Wait up to 5 seconds
                    if (process.ExitCode == 0)
                    {
                        Console.WriteLine("WinSCP executable verified successfully");
                    }
                }

                _resourcesInitialized = true;
                return true;
            }
            else
            {
                Console.WriteLine("Error: WinSCP.exe not found after extraction");
                return false;
            }
            #else
            Console.WriteLine("WinSCP auto-extraction not available on this platform");
            Console.WriteLine("Please install WinSCP manually");
            return false;
            #endif
        }
        catch (FileNotFoundException ex)
        {
            Console.WriteLine($"Embedded WinSCP resource not found: {ex.Message}");
            return false;
        }
        catch (UnauthorizedAccessException ex)
        {
            Console.WriteLine($"Permission denied extracting WinSCP: {ex.Message}");
            Console.WriteLine("Try running as administrator or check folder permissions");
            return false;
        }
        catch (InvalidOperationException ex) when (ex.Message.Contains("checksum"))
        {
            Console.WriteLine($"WinSCP file integrity check failed: {ex.Message}");
            Console.WriteLine("Embedded resource may be corrupted");
            return false;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Unexpected error initializing WinSCP: {ex.Message}");
            return false;
        }
    }

    public async Task<bool> TransferFileAsync(string localPath, string remotePath, 
        WinSCP.SessionOptions sessionOptions)
    {
        if (!InitializeWinScpResources())
        {
            throw new InvalidOperationException("WinSCP resources not available");
        }

        try
        {
            using (var session = new WinSCP.Session())
            {
                session.Open(sessionOptions);

                var transferResult = session.PutFiles(localPath, remotePath, false);
                transferResult.Check();

                Console.WriteLine($"Successfully transferred: {localPath} -> {remotePath}");
                return true;
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"File transfer failed: {ex.Message}");
            return false;
        }
    }
}

// Usage
var manager = new WinScpManager();

if (manager.InitializeWinScpResources())
{
    var sessionOptions = new WinSCP.SessionOptions
    {
        Protocol = WinSCP.Protocol.Sftp,
        HostName = "server.example.com",
        UserName = "ftpuser",
        Password = "password123"
    };

    await manager.TransferFileAsync(@"C:\data\report.pdf", "/uploads/report.pdf", sessionOptions);
}
else
{
    Console.WriteLine("Cannot proceed without WinSCP resources");
}

public class CrossPlatformFileTransfer
{
    public static void Initialize()
    {
        #if NETFRAMEWORK
        Console.WriteLine("Initializing for .NET Framework deployment");
        try
        {
            Core.EnsureWinSCP();
            Console.WriteLine("✓ WinSCP embedded resources extracted");
            Console.WriteLine("✓ Ready for Windows SFTP operations");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"✗ WinSCP initialization failed: {ex.Message}");
            Console.WriteLine("  File transfer functionality will be limited");
        }
        #endif

        #if NETCOREAPP || NET5_0_OR_GREATER
        Console.WriteLine("Initializing for .NET Core/.NET 5+ deployment");
        Console.WriteLine("Note: WinSCP must be installed separately on this platform");

        // Check if WinSCP is available in PATH
        if (IsWinScpInPath())
        {
            Console.WriteLine("✓ WinSCP found in system PATH");
        }
        else if (IsWinScpInLocalDirectory())
        {
            Console.WriteLine("✓ WinSCP found in application directory");
        }
        else
        {
            Console.WriteLine("✗ WinSCP not found");
            Console.WriteLine("  Install WinSCP or copy WinSCP.exe to application directory");
        }
        #endif
    }

    #if NETCOREAPP || NET5_0_OR_GREATER
    private static bool IsWinScpInPath()
    {
        try
        {
            var process = new Process
            {
                StartInfo = new ProcessStartInfo
                {
                    FileName = "WinSCP.exe",
                    Arguments = "/help",
                    UseShellExecute = false,
                    CreateNoWindow = true
                }
            };

            process.Start();
            process.WaitForExit(2000);
            return process.ExitCode == 0;
        }
        catch
        {
            return false;
        }
    }

    private static bool IsWinScpInLocalDirectory()
    {
        string localWinScp = Path.Combine(
            Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location),
            "WinSCP.exe"
        );
        return File.Exists(localWinScp);
    }
    #endif

    public static void ShowDeploymentInstructions()
    {
        Console.WriteLine("Deployment Instructions:");
        Console.WriteLine("========================");

        #if NETFRAMEWORK
        Console.WriteLine(".NET Framework:");
        Console.WriteLine("- WinSCP is embedded in the assembly");
        Console.WriteLine("- No additional installation required");
        Console.WriteLine("- First run extracts WinSCP.exe and WinSCPnet.dll");
        Console.WriteLine("- Subsequent runs use extracted files");
        #endif

        #if NETCOREAPP || NET5_0_OR_GREATER
        Console.WriteLine(".NET Core/.NET 5+:");
        Console.WriteLine("- Install WinSCP separately:");
        Console.WriteLine("  Option 1: Download from https://winscp.net");
        Console.WriteLine("  Option 2: Copy WinSCP.exe to application folder");
        Console.WriteLine("  Option 3: Add WinSCP to system PATH");
        Console.WriteLine("- Application will locate WinSCP automatically");
        #endif
    }
}

// Application startup
public class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("ByteForge File Transfer Application");
        Console.WriteLine("====================================");

        CrossPlatformFileTransfer.Initialize();

        // Show deployment info if WinSCP not available
        #if NETCOREAPP || NET5_0_OR_GREATER
        if (!IsWinScpAvailable())
        {
            CrossPlatformFileTransfer.ShowDeploymentInstructions();
            return;
        }
        #endif

        // Continue with application logic
        RunFileTransferOperations();
    }

    static void RunFileTransferOperations()
    {
        Console.WriteLine("File transfer operations ready");
        // Application-specific logic here
    }

    #if NETCOREAPP || NET5_0_OR_GREATER
    static bool IsWinScpAvailable()
    {
        // Check if WinSCP is available for use
        try
        {
            using (var session = new WinSCP.Session())
            {
                // If we can create a session, WinSCP is available
                return true;
            }
        }
        catch
        {
            return false;
        }
    }
    #endif
}

using ByteForge.Toolkit;
using System;
using System.Diagnostics;
using System.IO;
using System.Reflection;
using System.Threading.Tasks;

// Enterprise file transfer service using Core module
public class EnterpriseFileTransferService
{
    private readonly ILogger _logger;
    private bool _winScpInitialized = false;

    public EnterpriseFileTransferService(ILogger logger)
    {
        _logger = logger;
    }

    public bool InitializeFileTransferCapabilities()
    {
        try
        {
            _logger.Info("Initializing file transfer capabilities...");

            #if NETFRAMEWORK
            _logger.Info("Platform: .NET Framework - using embedded WinSCP resources");

            var stopwatch = Stopwatch.StartNew();
            Core.EnsureWinSCP();
            stopwatch.Stop();

            _logger.Info($"WinSCP resources extracted in {stopwatch.ElapsedMilliseconds}ms");

            // Verify extracted files
            VerifyWinScpInstallation();

            #else
            _logger.Info("Platform: .NET Core/.NET 5+ - checking external WinSCP installation");

            if (!VerifyExternalWinScp())
            {
                _logger.Error("WinSCP not found. Please install WinSCP or copy to application directory");
                return false;
            }

            _logger.Info("External WinSCP installation verified");
            #endif

            _winScpInitialized = true;
            _logger.Info("File transfer capabilities initialized successfully");
            return true;
        }
        catch (Exception ex)
        {
            _logger.Error("Failed to initialize file transfer capabilities", ex);
            return false;
        }
    }

    private void VerifyWinScpInstallation()
    {
        string appDir = Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location);
        string winScpExe = Path.Combine(appDir, "WinSCP.exe");
        string winScpDll = Path.Combine(appDir, "WinSCPnet.dll");

        var filesToCheck = new[]
        {
            new { Path = winScpExe, Name = "WinSCP.exe" },
            new { Path = winScpDll, Name = "WinSCPnet.dll" }
        };

        foreach (var file in filesToCheck)
        {
            if (File.Exists(file.Path))
            {
                var fileInfo = new FileInfo(file.Path);
                _logger.Info($"✓ {file.Name}: {fileInfo.Length:N0} bytes, modified {fileInfo.LastWriteTime}");

                // Verify file is not corrupted
                try
                {
                    using (var stream = File.OpenRead(file.Path))
                    {
                        if (stream.Length > 0)
                        {
                            _logger.Debug($"✓ {file.Name}: File readable and not empty");
                        }
                    }
                }
                catch (Exception ex)
                {
                    _logger.Warning($"⚠ {file.Name}: File verification failed - {ex.Message}");
                }
            }
            else
            {
                throw new FileNotFoundException($"Required file not found: {file.Name}");
            }
        }
    }

    #if NETCOREAPP || NET5_0_OR_GREATER
    private bool VerifyExternalWinScp()
    {
        // Check application directory first
        string appDir = Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location);
        string localWinScp = Path.Combine(appDir, "WinSCP.exe");

        if (File.Exists(localWinScp))
        {
            _logger.Info($"Found WinSCP in application directory: {localWinScp}");
            return true;
        }

        // Check system PATH
        try
        {
            var process = new Process
            {
                StartInfo = new ProcessStartInfo
                {
                    FileName = "WinSCP.exe",
                    Arguments = "/help",
                    UseShellExecute = false,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true,
                    CreateNoWindow = true
                }
            };

            process.Start();
            bool exited = process.WaitForExit(5000);

            if (exited && process.ExitCode == 0)
            {
                _logger.Info("Found WinSCP in system PATH");
                return true;
            }
        }
        catch (Exception ex)
        {
            _logger.Debug($"WinSCP not found in PATH: {ex.Message}");
        }

        return false;
    }
    #endif

    public async Task<TransferResult> TransferFileAsync(TransferRequest request)
    {
        if (!_winScpInitialized)
        {
            throw new InvalidOperationException("File transfer not initialized. Call InitializeFileTransferCapabilities() first");
        }

        var result = new TransferResult
        {
            RequestId = request.Id,
            StartTime = DateTime.UtcNow
        };

        try
        {
            _logger.Info($"Starting file transfer: {request.LocalPath} -> {request.RemotePath}");

            using (var session = new WinSCP.Session())
            {
                // Configure session logging
                session.FileTransferProgress += (sender, e) =>
                {
                    if (e.OverallProgress > 0)
                    {
                        _logger.Debug($"Transfer progress: {e.OverallProgress:P1} ({e.BytesTransferred:N0} bytes)");
                    }
                };

                // Open session
                session.Open(request.SessionOptions);
                _logger.Debug("SFTP session opened successfully");

                // Configure transfer options
                var transferOptions = new WinSCP.TransferOptions
                {
                    TransferMode = request.TransferMode,
                    FilePermissions = request.FilePermissions,
                    PreserveTimestamp = request.PreserveTimestamp,
                    ResumeSupport = WinSCP.TransferResumeSupport.On
                };

                // Perform transfer
                WinSCP.TransferOperationResult transferResult;
                if (request.Direction == TransferDirection.Upload)
                {
                    transferResult = session.PutFiles(request.LocalPath, request.RemotePath, request.DeleteSource, transferOptions);
                }
                else
                {
                    transferResult = session.GetFiles(request.RemotePath, request.LocalPath, request.DeleteSource, transferOptions);
                }

                // Check for errors
                transferResult.Check();

                result.Success = true;
                result.TransferredFiles = transferResult.Transfers.Count;
                result.TotalBytes = transferResult.Transfers
                    .Sum(t => new FileInfo(t.FileName).Length);

                _logger.Info($"Transfer completed: {result.TransferredFiles} files, {result.TotalBytes:N0} bytes");
            }
        }
        catch (Exception ex)
        {
            result.Success = false;
            result.ErrorMessage = ex.Message;
            result.Exception = ex;

            _logger.Error($"Transfer failed for request {request.Id}", ex);
        }
        finally
        {
            result.EndTime = DateTime.UtcNow;
            result.Duration = result.EndTime - result.StartTime;
        }

        return result;
    }

    public void GenerateDeploymentReport()
    {
        var report = new StringBuilder();
        report.AppendLine("ByteForge Core Module Deployment Report");
        report.AppendLine("======================================");
        report.AppendLine($"Generated: {DateTime.Now:yyyy-MM-dd HH:mm:ss}");
        report.AppendLine();

        // Platform information
        report.AppendLine("Platform Information:");
        #if NETFRAMEWORK
        report.AppendLine($"  Target Framework: .NET Framework");
        report.AppendLine($"  WinSCP Deployment: Embedded resources");
        #else
        report.AppendLine($"  Target Framework: .NET Core/.NET 5+");
        report.AppendLine($"  WinSCP Deployment: External installation required");
        #endif
        report.AppendLine($"  Operating System: {Environment.OSVersion}");
        report.AppendLine($"  Machine Name: {Environment.MachineName}");
        report.AppendLine();

        // File system information
        string appDir = Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location);
        report.AppendLine("File System:");
        report.AppendLine($"  Application Directory: {appDir}");

        var filesToCheck = new[] { "WinSCP.exe", "WinSCPnet.dll" };
        foreach (string fileName in filesToCheck)
        {
            string filePath = Path.Combine(appDir, fileName);
            if (File.Exists(filePath))
            {
                var fileInfo = new FileInfo(filePath);
                report.AppendLine($"  ✓ {fileName}: {fileInfo.Length:N0} bytes ({fileInfo.LastWriteTime:yyyy-MM-dd HH:mm:ss})");
            }
            else
            {
                report.AppendLine($"  ✗ {fileName}: Not found");
            }
        }

        report.AppendLine();

        // Initialization status
        report.AppendLine("Initialization Status:");
        report.AppendLine($"  WinSCP Initialized: {_winScpInitialized}");

        if (_winScpInitialized)
        {
            report.AppendLine("  Status: ✓ Ready for file transfer operations");
        }
        else
        {
            report.AppendLine("  Status: ✗ File transfer not available");
            #if NETCOREAPP || NET5_0_OR_GREATER
            report.AppendLine("  Action Required: Install WinSCP or copy to application directory");
            #endif
        }

        var reportContent = report.ToString();
        _logger.Info($"Deployment Report:\n{reportContent}");

        // Save report to file
        string reportPath = Path.Combine(appDir, "deployment_report.txt");
        File.WriteAllText(reportPath, reportContent);
        _logger.Info($"Deployment report saved to: {reportPath}");
    }
}

// Supporting classes
public class TransferRequest
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string LocalPath { get; set; }
    public string RemotePath { get; set; }
    public TransferDirection Direction { get; set; }
    public WinSCP.SessionOptions SessionOptions { get; set; }
    public WinSCP.TransferMode TransferMode { get; set; } = WinSCP.TransferMode.Binary;
    public WinSCP.FilePermissions FilePermissions { get; set; }
    public bool PreserveTimestamp { get; set; } = true;
    public bool DeleteSource { get; set; } = false;
}

public enum TransferDirection
{
    Upload,
    Download
}

public class TransferResult
{
    public string RequestId { get; set; }
    public bool Success { get; set; }
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public TimeSpan Duration { get; set; }
    public int TransferredFiles { get; set; }
    public long TotalBytes { get; set; }
    public string ErrorMessage { get; set; }
    public Exception Exception { get; set; }
}

// Main application
public class FileTransferApplication
{
    private readonly ILogger _logger;
    private readonly EnterpriseFileTransferService _transferService;

    public FileTransferApplication(ILogger logger)
    {
        _logger = logger;
        _transferService = new EnterpriseFileTransferService(logger);
    }

    public async Task RunAsync()
    {
        _logger.Info("Starting file transfer application");

        try
        {
            // Initialize file transfer capabilities
            if (!_transferService.InitializeFileTransferCapabilities())
            {
                _logger.Error("Failed to initialize file transfer - application cannot continue");
                return;
            }

            // Generate deployment report
            _transferService.GenerateDeploymentReport();

            // Example file transfer
            await PerformSampleTransfer();

            _logger.Info("Application completed successfully");
        }
        catch (Exception ex)
        {
            _logger.Fatal("Application failed", ex);
            throw;
        }
    }

    private async Task PerformSampleTransfer()
    {
        var request = new TransferRequest
        {
            LocalPath = @"C:\data\sample.txt",
            RemotePath = "/uploads/sample.txt",
            Direction = TransferDirection.Upload,
            SessionOptions = new WinSCP.SessionOptions
            {
                Protocol = WinSCP.Protocol.Sftp,
                HostName = "sftp.example.com",
                UserName = "username",
                Password = "password"
            }
        };

        var result = await _transferService.TransferFileAsync(request);

        if (result.Success)
        {
            _logger.Info($"Sample transfer completed: {result.TransferredFiles} files in {result.Duration.TotalSeconds:F2}s");
        }
        else
        {
            _logger.Error($"Sample transfer failed: {result.ErrorMessage}");
        }
    }
}

// Program entry point
public class Program
{
    static async Task Main(string[] args)
    {
        // Setup logging (placeholder - use actual logging framework)
        var logger = new ConsoleLogger();

        var app = new FileTransferApplication(logger);

        try
        {
            await app.RunAsync();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Critical error: {ex.Message}");
            Environment.Exit(1);
        }
    }
}

// Simple logger implementation for example
public class ConsoleLogger : ILogger
{
    public void Debug(string message) => Console.WriteLine($"[DEBUG] {message}");
    public void Info(string message) => Console.WriteLine($"[INFO] {message}");
    public void Warning(string message) => Console.WriteLine($"[WARN] {message}");
    public void Error(string message, Exception ex = null) => Console.WriteLine($"[ERROR] {message}" + (ex != null ? $" - {ex.Message}" : ""));
    public void Fatal(string message, Exception ex = null) => Console.WriteLine($"[FATAL] {message}" + (ex != null ? $" - {ex.Message}" : ""));
}

public interface ILogger
{
    void Debug(string message);
    void Info(string message);
    void Warning(string message);
    void Error(string message, Exception ex = null);
    void Fatal(string message, Exception ex = null);
}
